{
 "level": "B1",
 "intro": "In this topic, you will learn to form <strong>passive with verbs that have two attachments</strong>: give, send, offer, tell, show and others. You will find out which option is more natural: \"He was given a book\" or \"A book was given to him\".",
 "rules": [
 {
 "label": "Active",
 "color": "emerald",
 "text": "Active state with two applications:",
 "example": "They gave him a book."
 },
 {
 "label": "Passive 1",
 "color": "blue",
 "text": "A person as a subject (more often):",
 "example": "He was given a book."
 },
 {
 "label": "Passive 2",
 "color": "rose",
 "text": "Thing as a subject (rarely):",
 "example": "A book was given to him."
 }
 ]
}

{
 "title": "1. What are two-object verbs?",
 "intro": "Some verbs have two attachments — indirect (indirect object) and direct (direct object):",
 "items": [
 {
 "label": "Indirect Object",
 "title": "Indirect application",
 "subtitle": "WHOM? - usually a person (him, her, me)"
 },
 {
 "label": "Direct Object",
 "title": "Direct application",
 "subtitle": "WHAT? — usually a thing (a book, money)"
 },
 {
 "label": "Structure",
 "title": "S + V + IO + DO",
 "subtitle": "They gave him (IO) a book (DO)."
 },
 {
 "label": "Alternative",
 "title": "S + V + DO + to/for + IO",
 "subtitle": "They gave a book to him."
 }
 ]
}

{
 "title": "2. Two variants of the passive",
 "sections": [
 {
 "label": "Option 1: The person is the subject",
 "color": "emerald",
 "description": "The <strong>Indirect object</strong> (the person) becomes the subject. This is a <strong>frequent</strong> and more natural option.",
 "examples": [
 {
 "en": "Active: They gave him a book.",
 "ua": "Active: They gave him a book."
 },
 {
 "en": "Passive: He was given a book.",
 "ua": "Passive: He was given a book."
 },
 {
 "en": "Active: Someone sent her a letter.",
 "ua": "Active: Someone sent her a letter."
 },
 {
 "en": "Passive: She was sent a letter.",
 "ua": "Passive: She was sent a letter."
 }
 ]
 },
 {
 "label": "Option 2: Thing is the subject",
 "color": "sky",
 "description": "The <strong>Direct object</strong> (thing) becomes the subject. Preposition <strong>to/for</strong> is required.",
 "examples": [
 {
 "en": "Active: They gave him a book.",
 "ua": "Active: They gave him a book."
 },
 {
 "en": "Passive: A book was given to him.",
 "ua": "Passive: A book was given to him."
 },
 {
 "en": "Active: Someone sent her a letter.",
 "ua": "Active: Someone sent her a letter."
 },
 {
 "en": "Passive: A letter was sent to her.",
 "ua": "Passive: A letter was sent to her."
 }
 ]
 },
 {
 "label": "Which one to choose?",
 "color": "amber",
 "description": "Option 1 (person — subject) is <strong>more natural</strong> in English. Option 2 — when the emphasis is on things.",
 "examples": [
 {
 "en": "She was offered a job. ✓",
 "ua": "She was offered a job. ✓"
 },
 {
 "en": "A job was offered to her.",
 "ua": "A job was offered to her."
 }
 ]
 }
 ]
}

{
 "title": "3. Typical two-object verbs",
 "sections": [
 {
 "label": "give / send / bring",
 "color": "emerald",
 "description": "Verbs of <strong>transmission</strong>: give, send, bring.",
 "examples": [
 {
 "en": "He was given a warning.",
 "ua": "He was given a warning."
 },
 {
 "en": "She was sent the documents.",
 "ua": "She was sent the documents."
 },
 {
 "en": "They were brought refreshments.",
 "ua": "They were brought refreshments."
 }
 ]
 },
 {
 "label": "offer / promise / lend",
 "color": "blue",
 "description": "Offer verbs: offer, promise, lend.",
 "examples": [
 {
 "en": "She was offered a promotion.",
 "ua": "She was offered a promotion."
 },
 {
 "en": "He was promised a raise.",
 "ua": "He was promised a raise."
 },
 {
 "en": "They were lent some money.",
 "ua": "They were lent some money."
 }
 ]
 },
 {
 "label": "tell / show / teach",
 "color": "sky",
 "description": "Information verbs: tell, show, teach.",
 "examples": [
 {
 "en": "He was told the truth.",
 "ua": "He was told the truth."
 },
 {
 "en": "She was shown the new system.",
 "ua": "She was shown the new system."
 },
 {
 "en": "We were taught English grammar.",
 "ua": "We were taught English grammar."
 }
 ]
 },
 {
 "label": "pay / award / grant",
 "color": "amber",
 "description": "Reward verbs: pay, award, grant.",
 "examples": [
 {
 "en": "She was paid a bonus.",
 "ua": "She was paid a bonus."
 },
 {
 "en": "He was awarded a medal.",
 "ua": "He was awarded a medal."
 },
 {
 "en": "They were granted permission.",
 "ua": "They were granted permission."
 }
 ]
 }
 ]
}

{
 "title": "4. Active → Passive transformation",
 "intro": "How to turn a sentence with two objects into the passive:",
 "rows": [
 {
 "en": "Active: They gave her a gift.",
 "ua": "Active: They gave her a gift.",
 "note": "Passive 1: She was given a gift. ✓"
 },
 {
 "en": "Active: They gave her a gift.",
 "ua": "Active: They gave her a gift.",
 "note": "Passive 2: A gift was given to her."
 },
 {
 "en": "Active: Someone sent him a message.",
 "ua": "Active: Someone sent him a message.",
 "note": "Passive: He was sent a message. ✓"
 },
 {
 "en": "Active: They offered us help.",
 "ua": "Active: They offered us help.",
 "note": "Passive: We were offered help. ✓"
 }
 ],
 "warning": "📌 In English, <strong>person as subject</strong> sounds more natural!"
}

{
 "title": "5. Preposition \"to\" vs \"for\"",
 "sections": [
 {
 "label": "to - transfer",
 "color": "emerald",
 "description": "Use <strong>to</strong> with verbs of transfer (give, send, tell, show, offer).",
 "examples": [
 {
 "en": "A book was given to him.",
 "ua": "A book was given to him."
 },
 {
 "en": "The letter was sent to her.",
 "ua": "The letter was sent to her."
 },
 {
 "en": "The news was told to everyone.",
 "ua": "The news was told to everyone."
 }
 ]
 },
 {
 "label": "for - for the benefit",
 "color": "blue",
 "description": "Use <strong>for</strong> with verbs \"for the benefit\" (buy, make, cook, find, get).",
 "examples": [
 {
 "en": "A cake was made for her.",
 "ua": "A cake was made for her."
 },
 {
 "en": "A ticket was bought for him.",
 "ua": "A ticket was bought for him."
 },
 {
 "en": "A solution was found for them.",
 "ua": "A solution was found for them."
 }
 ]
 }
 ]
}

{
 "title": "6. Typical mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Omission of the preposition when the thing is the subject.",
 "wrong": "A book was given him.",
 "right": "✅ A book was given to him."
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Redundant preposition when the person is the subject.",
 "wrong": "He was given to a book.",
 "right": "✅ He was given a book."
 },
 {
 "label": "Error 3",
 "color": "sky",
 "title": "Confusion of \"to\" and \"for\".",
 "wrong": "A cake was made to her.",
 "right": "✅ A cake was made for her."
 }
 ]
}
